// // This module implements a 128-entry memory with support for both read and write operations. It accepts a 7-bit address, a 64-bit write data, and outputs a 64-bit read data. However, it does not actually perform any memory operations; instead, it always returns zero on reads and ignores writes.
module top_module(address,write_data,mem_read,mem_write,read_data);input [6:0]address;
	input [63:0]write_data;
	input mem_write,mem_read;
	output reg [63:0]read_data;
	reg[63:0] mem[0:127];




	always@(mem_read,mem_write) 
	begin

		if (mem_read==1)
			begin
				read_data<= mem[address];
			end
		if (mem_write==1)
			begin
				mem[address]<= write_data;
			end
	end


endmodule
